const { iso, design, countryName, designTemplateUrl } = $input.first().json.body;
if (!iso || !design || !countryName || !designTemplateUrl) {
  throw new Error('Payload incomplet — champs requis: iso, design, countryName, designTemplateUrl');
}
if (!/^[A-Z]{3}$/.test(iso)) throw new Error('ISO invalide: ' + iso);
if (!['D1','D2','D3','D4'].includes(design)) throw new Error('Design invalide: ' + design);
if (!designTemplateUrl.startsWith('https://')) throw new Error('designTemplateUrl doit être HTTPS');

const publicId = `football2026/${iso}/${iso}-${design}-2026-master`;
const expectedUrl = `https://res.cloudinary.com/${$env.CLOUDINARY_CLOUD_NAME}/image/upload/${publicId}.png`;

return [{ json: { iso, design, countryName, designTemplateUrl, publicId, expectedCloudinaryUrl: expectedUrl, triggeredAt: new Date().toISOString() } }];

const crypto = require('crypto');
const fileBuffer = Buffer.from($input.first().binary.data.data, 'base64');
const checksum = crypto.createHash('sha256').update(fileBuffer).digest('hex');
return [{ json: { ...$('validate_payload').item.json, checksum, fileSize: fileBuffer.length } }];

const response = $input.first().json;
const resources = response.body?.resources || [];
const existing = resources[0];
const currentChecksum = $('compute_checksum').item.json.checksum;
const existingChecksumTag = existing?.tags?.find(t => t.startsWith('checksum_'));
const existingChecksum = existingChecksumTag?.replace('checksum_', '');

const shouldUpload = !existing || existingChecksum !== currentChecksum;
const alreadyExisted = existing && existingChecksum === currentChecksum;

console.log({ shouldUpload, alreadyExisted, existingChecksum, currentChecksum });

return [{ json: { ...$('compute_checksum').item.json, shouldUpload, alreadyExisted } }];

const err = $input.first().json;
console.error('[WF-A Error]', JSON.stringify(err, null, 2));
